12→  if (!user) redirect('/login');
13→
14→  const { data: merchant } = await supabase
15→    .from('merchants')
16→    .select('id, plan')
17→    .eq('user_id', user.id)
18→    .single();
19→
20→  if (!merchant) redirect('/register');
21→
22→  const { data: campaigns } = await supabase
23→    .from('campaigns')
