11→function shuffle<T>(arr: T[]): T[] {
12→  for (let i = arr.length - 1; i > 0; i--) {
13→    const j = Math.floor(Math.random() * (i + 1));
14→    [arr[i], arr[j]] = [arr[j], arr[i]];
