17→    const ninetyDaysAgo = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000).toISOString();
18→    let updated = 0;
19→
20→    // Get all customer cards with their programs
21→    const { data: cards } = await supabase
22→      .from('customer_cards')
23→      .select('id, customer_id, current_points, tier, program_id, customers(push_token)');
24→
25→    for (const card of cards ?? []) {
26→      // Count transactions in last 90 days
27→      const { count: txCount } = await supabase
28→        .from('transactions')
29→        .select('id', { count: 'exact', head: true })
30→        .eq('card_id', card.id)
31→        .gte('created_at', ninetyDaysAgo);
32→
33→      // Get tier rules for this program, ordered by min_transactions desc (highest tier first)
34→      const { data: rules } = await supabase
35→        .from('tier_rules')
36→        .select('*')
37→        .eq('program_id', card.program_id)
38→        .order('min_transactions', { ascending: false });
39→
40→      if (!rules || rules.length === 0) continue;
41→
42→      // Determine highest qualifying tier
43→      let newTier = 'bronze';
44→      for (const rule of rules) {
45→        if ((txCount ?? 0) >= rule.min_transactions && card.current_points >= (rule.min_points ?? 0)) {
46→          newTier = rule.tier;
47→          break; // rules sorted desc, first match is highest tier
48→        }
49→      }
