 1→import { NextResponse } from 'next/server';
 2→import Stripe from 'stripe';
 3→import { getStripe } from '@/lib/stripe';
 4→import { createClient as createSupabaseAdmin } from '@supabase/supabase-js';
 5→
 6→// Use admin client (service role) for webhook processing
 7→function getAdminClient() {
 8→  return createSupabaseAdmin(
 9→    process.env.NEXT_PUBLIC_SUPABASE_URL!,
10→    process.env.SUPABASE_SERVICE_ROLE_KEY!
11→  );
12→}
