50→        <div className="px-4 pb-4 border-t border-[var(--border-default)] bg-black/20">
51→          <div className="mt-3 space-y-3">
52→            {category.items.map((item, idx) => (
53→              <div key={idx} className="flex items-start gap-3 text-sm p-2 rounded-xl hover:bg-[var(--glass-surface)] transition-colors">
54→                <span className="mt-0.5">{getStatusIcon(item.status)}</span>
55→                <span className="text-gray-300">{item.message}</span>
56→              </div>
57→            ))}
58→          </div>
59→        </div>
60→      )}
61→    </div>
62→  );
63→};
64→
65→export default CategoryCard;
